// LESSON: Reference Page 1 - Referenser, varden, null.
// You will learn: Track primitive copies, object references, and null guards.
class Prog2Reference423 {
  // EXEMPEL 1: Primitiva typer kopieras som direkta varden.
  static int primitiveCopy() {
    int first = 5;
    int second = first;
    second = 9;
    return first;
  }
  // EXEMPEL 2: Klasstyper kopierar referensen, inte objektet.
  static class Note {
    String text;
    Note(String text) { this.text = text; }
  }
  static String referenceCopy() {
    Note a = new Note("start");
    Note b = a;
    b.text = "changed";
    return a.text;
  }
  // EXEMPEL 3: null betyder att variabeln inte pekar pa nagot objekt.
  static int safeLength(String text) {
    if (text == null) { return 0; }
    return text.length();
  }
}
